85: // `PendingPredicateObligation` is used a lot. Make sure it doesn't unintentionally get bigger.
86: #[cfg(target_pointer_width = "64")]
87: rustc_data_structures::static_assert_size!(PendingPredicateObligation<'_>, 72);
